import sys

def solve():
    it = iter(sys.stdin.read().strip().split())
    t = int(next(it))
    out = []
    for _ in range(t):
        n = int(next(it))
        a = [int(next(it)) for _ in range(n)]
        best = 0
        for i in range(n):
            prod = 1
            for j, x in enumerate(a):
                if j == i:
                    prod *= (x + 1)
                else:
                    prod *= x
            if prod > best:
                best = prod
        out.append(str(best))
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()
