from typing import List

class Solution:
    def countSeniors(self, details: List[str]) -> int:
        ans = 0
        for d in details:
            # Age is encoded in characters 11 and 12 (0-indexed: indices 11..12)
            age = int(d[11:13])
            if age > 60:
                ans += 1
        return ans
